import tarfile
import os

def extract_tar(tar_filepath, dest_dir):
    """
    Extracts a tar file to a specified destination directory.

    Args:
        tar_filepath (str): The path to the tar file to be extracted.
        dest_dir (str): The path to the destination directory where the
                        contents of the tar file will be extracted.

    Raises:
        FileNotFoundError: If tar_filepath does not exist.
        tarfile.ReadError: If the file is not a valid tar file.
        Exception: For other potential errors during extraction.
    """
    if not os.path.exists(tar_filepath):
        raise FileNotFoundError(f"Tar file not found: {tar_filepath}")

    if not os.path.isdir(dest_dir):
        os.makedirs(dest_dir, exist_ok=True)

